//! Categorical data types with contrast coding for statistical modeling
//!
//! This crate provides first-class types for categorical data, featuring
//! pluggable contrast coding (dummy, sum-to-zero, Helmert, etc.) and
//! support for ordered factors.

#![forbid(unsafe_code)]
#![warn(missing_docs)]

use std::sync::Arc;

/// A categorical factor with shared level storage
#[derive(Debug, Clone)]
pub struct Factor<T> {
    /// Level indices for each observation
    indices: Vec<u32>,
    /// Shared level labels
    levels: Arc<Vec<T>>,
}

/// An ordered categorical factor  
#[derive(Debug, Clone)]
pub struct OrderedFactor<T>(Factor<T>);

/// Trait for contrast coding schemes
pub trait Contrast {
    /// Generate contrast matrix for the given number of levels
    fn matrix(&self, n_levels: usize) -> Vec<Vec<f64>>;

    /// Number of columns produced by this contrast
    fn n_cols(&self, n_levels: usize) -> usize;
}

/// Treatment (dummy) coding - first level is reference
#[derive(Debug, Default)]
pub struct Dummy;

impl Contrast for Dummy {
    fn matrix(&self, n_levels: usize) -> Vec<Vec<f64>> {
        let mut matrix = Vec::new();
        for i in 1..n_levels {
            let mut row = vec![0.0; n_levels - 1];
            row[i - 1] = 1.0;
            matrix.push(row);
        }
        matrix
    }

    fn n_cols(&self, n_levels: usize) -> usize {
        if n_levels <= 1 {
            0
        } else {
            n_levels - 1
        }
    }
}

/// Sum-to-zero coding
#[derive(Debug, Default)]
pub struct Sum;

impl Contrast for Sum {
    fn matrix(&self, n_levels: usize) -> Vec<Vec<f64>> {
        let mut matrix = Vec::new();
        for i in 0..(n_levels - 1) {
            let mut row = vec![-1.0; n_levels - 1];
            if i < n_levels - 1 {
                row[i] = 1.0;
            }
            matrix.push(row);
        }
        matrix
    }

    fn n_cols(&self, n_levels: usize) -> usize {
        if n_levels <= 1 {
            0
        } else {
            n_levels - 1
        }
    }
}

impl<T> Factor<T>
where
    T: Clone + PartialEq,
{
    /// Create a new factor from a vector of values
    pub fn from_vec(values: Vec<T>) -> Self {
        let mut levels = Vec::new();
        let mut indices = Vec::new();

        for value in values {
            if let Some(index) = levels.iter().position(|level| level == &value) {
                indices.push(index as u32);
            } else {
                levels.push(value);
                indices.push((levels.len() - 1) as u32);
            }
        }

        Self {
            indices,
            levels: Arc::new(levels),
        }
    }

    /// Get the number of levels
    pub fn n_levels(&self) -> usize {
        self.levels.len()
    }

    /// Get level labels
    pub fn levels(&self) -> &[T] {
        &self.levels
    }

    /// Get indices
    pub fn indices(&self) -> &[u32] {
        &self.indices
    }
}

//! R-style formula parsing and design matrix specification
//!
//! This crate provides compile-time and run-time parsing of statistical formulas
//! in the R format (e.g., `y ~ x1 + x2*x3`), compiling them into optimized
//! design matrix generators.

#![forbid(unsafe_code)]
#![warn(missing_docs)]

/// Formula parsing errors
#[derive(thiserror::Error, Debug)]
pub enum FormulaError {
    /// Parse error from pest
    #[error("Formula parse error: {0}")]
    Parse(String),
    /// Semantic validation error
    #[error("Formula validation error: {0}")]
    Validation(String),
}

/// Abstract syntax tree representing a parsed statistical formula
#[derive(Debug, Clone, PartialEq)]
pub struct ModelSpec {
    /// The response variable(s)
    pub response: Vec<String>,
    /// The predictor terms
    pub terms: Vec<Term>,
}

/// A term in a statistical formula
#[derive(Debug, Clone, PartialEq)]
pub enum Term {
    /// Intercept term
    Intercept,
    /// Variable name
    Variable(String),
    /// Interaction between terms
    Interaction(Vec<Term>),
    /// Function call (e.g., I(x^2), poly(x, 2))
    Function { name: String, args: Vec<String> },
}

impl ModelSpec {
    /// Create a simple formula with intercept
    pub fn intercept_only(response: &str) -> Self {
        Self {
            response: vec![response.to_string()],
            terms: vec![Term::Intercept],
        }
    }

    /// Add a variable term
    pub fn add_variable(&mut self, var: &str) {
        self.terms.push(Term::Variable(var.to_string()));
    }
}

/// Parse a formula string into a ModelSpec
pub fn parse_formula(_formula: &str) -> Result<ModelSpec, FormulaError> {
    // TODO: Implement pest-based parser in Sprint 2
    // For now, return a simple intercept-only model for testing
    Ok(ModelSpec::intercept_only("y"))
}

