//! ANOVA and experimental design tools
//!
//! This crate provides classical experimental design tools, including
//! Type I/II/III ANOVA and analysis of variance tables.

#![forbid(unsafe_code)]
#![warn(missing_docs)]

/// ANOVA table row
#[derive(Debug)]
pub struct AnovaRow {
    /// Source of variation
    pub source: String,
    /// Degrees of freedom
    pub df: i32,
    /// Sum of squares
    pub sum_sq: f64,
    /// Mean square
    pub mean_sq: f64,
    /// F-statistic
    pub f_value: f64,
    /// p-value
    pub p_value: f64,
}

/// ANOVA table
#[derive(Debug)]
pub struct AnovaTable {
    /// Table rows
    pub rows: Vec<AnovaRow>,
}

/// ANOVA type
#[derive(Debug)]
pub enum AnovaType {
    /// Type I (sequential)
    TypeI,
    /// Type II (hierarchical)
    TypeII,
    /// Type III (marginal)
    TypeIII,
}

/// Compute ANOVA table
pub fn anova(_model: &dyn std::any::Any, _anova_type: AnovaType) -> AnovaTable {
    // TODO: Implement ANOVA computation in future sprint
    // For now, return placeholder table for testing
    AnovaTable {
        rows: vec![AnovaRow {
            source: "Residuals".to_string(),
            df: 10,
            sum_sq: 1.0,
            mean_sq: 0.1,
            f_value: std::f64::NAN,
            p_value: std::f64::NAN,
        }],
    }
}

