use criterion::{black_box, criterion_group, criterion_main, Criterion, BenchmarkId};
use stats_models::Lm;
use std::time::Duration;

/// Generate a design matrix and response for benchmarking
fn generate_data(n_obs: usize, n_vars: usize) -> (Vec<f64>, Vec<f64>) {
    let mut x_data = Vec::with_capacity(n_obs * n_vars);
    let mut y_data = Vec::with_capacity(n_obs);

    // Generate design matrix with intercept column + random predictors
    for i in 0..n_obs {
        // Intercept
        x_data.push(1.0);

        // Random predictors
        for j in 1..n_vars {
            x_data.push((i as f64 + j as f64 * 0.1) % 10.0);
        }

        // Generate response: y = 1 + 2*x1 + 0.5*x2 + ... + noise
        let mut y = 1.0; // intercept
        for j in 1..n_vars {
            let predictor_val = x_data[i * n_vars + j];
            y += (j as f64) * 0.5 * predictor_val;
        }
        y += (i as f64 * 0.01) % 1.0; // small noise term
        y_data.push(y);
    }

    (x_data, y_data)
}

fn benchmark_ols_rust(c: &mut Criterion) {
    let mut group = c.benchmark_group("OLS_Rust");

    // Test different problem sizes
    let sizes = vec![
        (100, 5),    // Small: 100 obs, 5 vars
        (1000, 10),  // Medium: 1000 obs, 10 vars  
        (5000, 20),  // Large: 5000 obs, 20 vars
        (10000, 30), // XLarge: 10000 obs, 30 vars
    ];

    for (n_obs, n_vars) in sizes {
        let (x_data, y_data) = generate_data(n_obs, n_vars);

        group.bench_with_input(
            BenchmarkId::new("faer_qr", format!("{}x{}", n_obs, n_vars)),
            &(x_data, y_data, n_obs, n_vars),
            |b, (x, y, rows, cols)| {
                b.iter(|| {
                    let result = Lm::fit(
                        black_box(x),
                        black_box(y),
                        black_box(*rows),
                        black_box(*cols),
                    );
                    black_box(result.unwrap())
                })
            },
        );
    }

    group.finish();
}

/// Benchmark a realistic regression problem
fn benchmark_realistic_regression(c: &mut Criterion) {
    let mut group = c.benchmark_group("Realistic_Regression");

    // Simulate a typical statistical analysis
    let n_obs = 2000;
    let n_vars = 15; // 1 intercept + 14 predictors

    let (x_data, y_data) = generate_data(n_obs, n_vars);

    group.bench_function("typical_regression_2k_x_15", |b| {
        b.iter(|| {
            let result = Lm::fit(
                black_box(&x_data),
                black_box(&y_data),
                black_box(n_obs),
                black_box(n_vars),
            );
            black_box(result.unwrap())
        })
    });

    group.finish();
}

/// Test performance with different matrix aspect ratios
fn benchmark_matrix_shapes(c: &mut Criterion) {
    let mut group = c.benchmark_group("Matrix_Shapes");

    // Test wide vs tall matrices
    let shapes = vec![
        (1000, 5),   // Tall: many observations, few predictors
        (1000, 50),  // Square-ish: moderate obs, moderate predictors  
        (200, 50),   // Wide: fewer observations, many predictors
    ];

    for (n_obs, n_vars) in shapes {
        let (x_data, y_data) = generate_data(n_obs, n_vars);

        group.bench_with_input(
            BenchmarkId::new("shape", format!("{}x{}", n_obs, n_vars)),
            &(x_data, y_data, n_obs, n_vars),
            |b, (x, y, rows, cols)| {
                b.iter(|| {
                    let result = Lm::fit(
                        black_box(x),
                        black_box(y),
                        black_box(*rows),
                        black_box(*cols),
                    );
                    black_box(result.unwrap())
                })
            },
        );
    }

    group.finish();
}

criterion_group! {
    name = benches;
    config = Criterion::default()
        .measurement_time(Duration::from_secs(10))
        .sample_size(100);
    targets = 
        benchmark_ols_rust,
        benchmark_realistic_regression,
        benchmark_matrix_shapes
}

criterion_main!(benches);

