// In inference/src/lib.rs
use statrs::distribution::{StudentsT, ContinuousCDF};

/// Compute two-tailed p-values from t-statistics
pub fn t_test_p_values(t_stats: &[f64], df: i32) -> Vec<f64> {
    if df <= 0 {
        return vec![f64::NAN; t_stats.len()];
    }
    let t_dist = StudentsT::new(df as f64).unwrap();
